INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('03ad20f7-2663-463d-87ab-2e4872e132b4', '7e127abb-da46-4113-90e9-6e1731d574b7', 'caneca-300-liso', 'Caneca 300ml Liso', 'Caneca 300ml com acabamento liso. Design compacto e funcional, ideal para café, chá, bebidas quentes e frias, uso doméstico e comercial. Disponível em cores leitosas, translúcidas e neon. Volume de 300ml, espessura de 2mm, com alça.', 'produto', NULL, 'CNC3L', '176', NULL, 300, 'UN', NULL, 41.00, '{"altura": 10.3, "espessura": 2.0, "diametro_inferior": 6.6, "diametro_superior": 6.9, "largura_total_com_alca": 9.7}'::jsonb, '{"linha": "Standard", "familia": "Caneca", "tamanho": "pequena", "volume_ml": 300, "acabamento": "liso", "espessura_mm": 2.0, "caracteristicas": ["acabamento_liso", "design_compacto", "com_alca", "variedade_cores", "uso_domestico", "uso_comercial", "uso_cafe_cha"]}'::jsonb, true, true, '2025-11-13T12:20:28.504364+00:00'::timestamptz, '2025-11-13T12:20:28.504364+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('04122868-c544-462f-9d21-3d649786338a', '87fddf11-6c05-46ea-b6a8-4a03082bd455', 'sobretampa-super-bucks', 'Sobretampa Super Bucks', 'Sobretampa Super Bucks (parte superior, com alça). Produto complementar à Tampa Super Bucks base. IMPORTANTE: Para funcionar corretamente, é necessário comprar também a Tampa Super Bucks base. A tampa base e a sobretampa são vendidas separadamente e podem ser combinadas em cores diferentes, permitindo criar combinações personalizadas. Exemplo: sobretampa preta com tampa base azul neon, ou sobretampa creme marmorizado com tampa base branca. Cada parte é vendida em pacotes de 10 unidades da mesma cor. Exclusiva e compatível com Eco Duo.', 'acessorio', NULL, 'STMPSBKSL', '1446', NULL, NULL, 'UN', NULL, 12.00, '{"altura": 1.4, "espessura": null, "diametro_inferior": 9.2, "diametro_superior": null}'::jsonb, '{"familia": "Tampa", "tipo_acessorio": "sobretampa_super_bucks", "exclusiva_eco_duo": true, "produto_complementar": "tampa-super-bucks", "explicacao_combinacao": "A Sobretampa Super Bucks é um produto complementar à Tampa Super Bucks base. São dois produtos separados que funcionam juntos. O cliente pode comprar a sobretampa em uma cor e a tampa base em outra cor, criando combinações personalizadas. Por exemplo: sobretampa preta + tampa base azul neon, ou sobretampa creme marmorizado + tampa base branca. Cada parte é vendida separadamente em pacotes de 10 unidades da mesma cor. É importante sempre informar ao cliente que precisa comprar ambos os produtos para ter a Tampa Super Bucks completa funcionando. Esta tampa é exclusiva e compatível com o Eco Duo.", "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T10:00:15.845117+00:00'::timestamptz, '2025-11-13T10:00:15.845117+00:00'::timestamptz, NULL, NULL, NULL, NULL);
