INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('4215333c-d7d7-4036-9ec0-e70ea809c334', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-bio-preto-fosco', 'Garrafa Acqua Bio Preto Fosco', 'Garrafa Acqua Bio Preto Fosco 475ml com acabamento fosco. Design elegante e moderno com acabamento preto fosco, ideal para uso no dia a dia. Disponível em duas opções de cor interna: branco ou preto. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', NULL, 'GABPFL', '466', NULL, 475, 'UN', NULL, 68.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Bio", "familia": "Garrafa", "volume_ml": 475, "acabamento": "preto_fosco", "espessura_mm": 2, "cores_internas": ["branco", "preto"], "caracteristicas": ["acabamento_fosco", "preto_fosco", "design_elegante", "opcoes_cor_interna"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:37:50.034173+00:00'::timestamptz, '2025-11-13T10:37:50.034173+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('448cd060-7ce1-448f-849c-e033814d3bd6', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-bio-metalizado', 'Garrafa Acqua Bio Metalizado', 'Garrafa Acqua Bio com acabamento metalizado e interna cromada. Design elegante e moderno, ideal para uso no dia a dia. Disponível em diversas cores metalizadas sólidas e gradientes. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', 'Metalizado', 'GABML', '1199', NULL, 475, 'UN', NULL, 68.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Bio", "familia": "Garrafa", "volume_ml": 475, "acabamento": "metalizado", "espessura_mm": 2, "caracteristicas": ["interna_cromada", "acabamento_metalizado", "design_elegante"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:30:11.723931+00:00'::timestamptz, '2025-11-13T10:36:18.281118+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('450135ca-4ebd-4889-a695-0949d7a1960d', 'a2c0ccc8-273f-4606-9e75-62fa09a15939', 'taca-gin-degrade', 'Taça GIN Degradê 550ml', 'Taça GIN 550ml com acabamento degradê e bicolor. O produto inclui cores sólidas com efeito degradê e combinações bicolores. Todas as cores podem ser combinadas com borda metalizada. Dimensões: 19.7cm de altura, 10.2cm de diâmetro superior, 7.4cm de diâmetro inferior.', 'produto', NULL, 'TGDL', '374', NULL, 550, 'UN', NULL, 82.00, '{"altura": 19.7, "espessura": 3, "diametro_inferior": 7.4, "diametro_superior": 10.2}'::jsonb, '{"familia": "Taça GIN", "tamanho": "550ml", "volume_ml": 550, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Taça GIN Fosco Incolor (taca-gin-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto taca-gin-fosco-incolor.", "espessura_mm": 3, "tipo_acabamento": "degrade", "produto_relacionado": "taca-gin-fosco-incolor", "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T14:32:40.722490+00:00'::timestamptz, '2025-11-13T14:32:40.722490+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('4551ffae-5a17-45fb-9f6c-f260495cf0a2', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-eco', 'Garrafa Acqua Eco', 'Garrafa Acqua Eco 475ml com acabamento liso. Material PP (polipropileno), design elegante e moderno, ideal para uso no dia a dia. Disponível em diversas cores neon, translúcidas, leitosas e com acabamento fibra. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', NULL, 'GAECOL', '628', NULL, 475, 'UN', NULL, 55.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Eco", "familia": "Garrafa", "material": "PP", "volume_ml": 475, "acabamento": "liso", "espessura_mm": 2, "caracteristicas": ["acabamento_liso", "material_pp", "design_elegante", "variedade_cores"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T11:09:07.598929+00:00'::timestamptz, '2025-11-13T11:09:07.598929+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('45f843a8-e98e-480b-acaf-39516b654efd', 'b9bc6c78-fd03-4794-b28f-70b72772baf9', 'tulipa-liso', 'Tulipa Liso 300ml', 'Copo Tulipa com capacidade de 300ml. Design clássico estilo cerveja, ideal para cervejas artesanais, chopes e bebidas geladas. Formato elegante que realça o sabor e a apresentação da bebida. Disponível em cores neon, leitosas e translúcidas.', 'produto', NULL, 'TLPL', '560', NULL, 300, 'UN', NULL, 61.00, '{"altura": 14.2, "espessura": 2.0, "diametro_inferior": 5.4, "diametro_superior": 6.9}'::jsonb, '{"estilo": "cerveja", "familia": "Tulipa", "volume_ml": 300, "espessura_mm": 2.0, "uso_recomendado": ["cerveja", "chope", "cerveja_artesanal", "bebidas_geladas"], "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T12:59:15.078777+00:00'::timestamptz, '2025-11-13T12:59:15.078777+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('461ab349-fdcd-4b62-ba8c-8e7f03fc8b05', 'a2c0ccc8-273f-4606-9e75-62fa09a15939', 'taca-gin-light-fosco-incolor', 'Taça GIN Happy Light Fosco Incolor 600ml', 'Taça GIN Happy Light 600ml com acabamento fosco incolor (efeito gelado). Design leve e elegante com efeito visual gelado/translúcido fosco, ideal para drinks e bebidas geladas. Dimensões: 19.9cm de altura, 10.2cm de diâmetro superior, 7.4cm de diâmetro inferior. Espessura de 2mm, peso de 57g.', 'produto', NULL, 'THGLHTFIL', '836', NULL, 600, 'UN', NULL, 57.00, '{"altura": 19.9, "espessura": 2, "diametro_inferior": 7.4, "diametro_superior": 10.2}'::jsonb, '{"linha": "Happy", "efeito": "gelado", "familia": "Taça GIN", "tamanho": "Light", "volume_ml": 600, "acabamento": "fosco_incolor", "observacao": "Este produto é um SKU separado do degradê. Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', este é o produto correto.", "cor_externa": "fosco_incolor", "espessura_mm": 2, "caracteristicas": ["acabamento_fosco_incolor", "efeito_gelado", "design_elegante", "design_leve", "relacionado_degrade"], "produto_relacionado": "taca-gin-light-degrade"}'::jsonb, true, true, '2025-11-13T14:45:04.499836+00:00'::timestamptz, '2025-11-13T14:45:04.499836+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('47dc9deb-1d77-4e06-b1e8-ce46c6e9801b', '7e127abb-da46-4113-90e9-6e1731d574b7', 'caneca-slim-degrade-liso', 'Caneca Slim Degradê 400ml Liso', 'Caneca Slim 400ml com acabamento degradê (gradiente) e alça. Design premium e funcional, ideal para bebidas quentes e frias, café, chá e uso doméstico. Disponível em diversas cores degradê simples (branco para cor) e bicolor (duas cores). Volume de 400ml, espessura de 2.2mm. Efeito visual moderno com gradiente de cores.', 'produto', NULL, 'CNCSDL', '86', NULL, 400, 'UN', NULL, 73.00, '{"altura": 16.7, "espessura": 2.2, "altura_alca": 10.0, "diametro_inferior": 6.0, "diametro_superior": 7.0, "largura_total_com_alca": 10.0}'::jsonb, '{"linha": "Premium", "familia": "Caneca", "volume_ml": 400, "acabamento": "degrade", "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Caneca Slim Fosco Incolor (caneca-slim-fosco-incolor-liso). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto caneca-slim-fosco-incolor-liso.", "espessura_mm": 2.2, "tipo_degrade": "simples_e_bicolor", "caracteristicas": ["acabamento_degrade", "degrade_simples", "degrade_bicolor", "design_premium", "com_alca", "variedade_cores", "uso_domestico", "uso_cafe_cha"], "produto_relacionado": "caneca-slim-fosco-incolor-liso"}'::jsonb, true, true, '2025-11-13T12:38:27.201035+00:00'::timestamptz, '2025-11-13T12:38:27.201035+00:00'::timestamptz, NULL, NULL, NULL, NULL);
