INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('550f4f2e-1bd0-414f-9bf5-103c134350e2', '918495eb-c6f9-422c-89cc-4132bc9b6480', 'twister-premium-metalizado-duo', 'Twister Premium Metalizado Duo 550ml', 'Copo Twister Premium Metalizado Duo com capacidade de 550ml. Lançamento especial com externa metalizada prata e interna glitter. Design premium que combina acabamento metalizado externo com efeito glitter interno. Pinturas especiais podem apresentar marcas características do processo de pintura.', 'produto', NULL, 'TWSPMDL', '1452', NULL, 550, 'UN', NULL, 70.00, '{"altura": 14.0, "espessura": 2, "diametro_inferior": 6.5, "diametro_superior": 8.5}'::jsonb, '{"familia": "Twister", "tamanho": "G", "novidade": true, "volume_ml": 550, "cor_externa": "prata", "espessura_mm": 2, "interna_glitter": true, "tipo_acabamento": "metalizado_duo", "externa_metalizada": true, "observacao_pintura": "Pinturas especiais podem apresentar marcas características do processo de pintura"}'::jsonb, true, true, '2025-11-13T16:30:14.033191+00:00'::timestamptz, '2025-11-13T16:30:14.033191+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('55fb3e69-e5a4-4966-809e-07fdea46520e', '7e127abb-da46-4113-90e9-6e1731d574b7', 'caneca-slim-preto-fosco-liso', 'Caneca Slim 400ml Preto Fosco Liso', 'Caneca Slim 400ml com acabamento preto fosco e alça. Design premium e funcional, ideal para bebidas quentes e frias, café, chá e uso doméstico. Disponível em diversas cores internas leitosas e peroladas. Volume de 400ml, espessura de 2.2mm, acabamento externo preto fosco.', 'produto', NULL, 'CNCSPFL', '70', NULL, 400, 'UN', NULL, 73.00, '{"altura": 16.7, "espessura": 2.2, "diametro_inferior": 6.0, "diametro_superior": 7.0, "largura_total_com_alca": 10.0}'::jsonb, '{"linha": "Premium", "familia": "Caneca", "volume_ml": 400, "acabamento": "preto_fosco_liso", "cor_externa": "preto_fosco", "espessura_mm": 2.2, "caracteristicas": ["acabamento_preto_fosco", "design_premium", "com_alca", "variedade_cores_internas", "uso_domestico", "uso_cafe_cha"]}'::jsonb, true, true, '2025-11-13T12:45:08.517331+00:00'::timestamptz, '2025-11-13T12:45:08.517331+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('58ab3314-6181-423d-b733-bfe1edd5cf54', '945ebc87-9c2d-47b6-aa1d-05b61c4f1b4e', 'eco-400-degrade-liso', 'Eco 400 Degradê 400ml', 'Copo Eco 400 Degradê com capacidade de 400ml. Design ecológico e sustentável com efeito degradê (gradiente de cores). Ideal para bebidas quentes e frias. Disponível em 13 combinações de cores degradê exclusivas, incluindo degradês simples e bicolores. Produto com consciência ambiental e design diferenciado.', 'produto', NULL, 'ECO4DL', '890', NULL, 400, 'UN', NULL, 30.00, '{"altura": 13.0, "espessura": 1.3, "diametro_inferior": 5.9, "diametro_superior": 7.8}'::jsonb, '{"efeito": "gradiente", "familia": "Eco", "tamanho": "400ml", "linha_eco": true, "volume_ml": 400, "acabamento": "degrade", "espessura_mm": 1.3, "uso_recomendado": ["bebidas_quentes", "bebidas_frias", "sucos", "refrigerantes"], "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:09:26.917364+00:00'::timestamptz, '2025-11-13T13:09:26.917364+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('5cad3300-9c45-446b-a20f-d97dd944560d', '7e127abb-da46-4113-90e9-6e1731d574b7', 'caneca-slim-metalizada-liso', 'Caneca Slim Metalizada 400ml Liso', 'Caneca Slim 400ml com acabamento metalizado e alça. Design premium e funcional com acabamento metalizado externo e interior cromado. Ideal para bebidas quentes e frias, café, chá e uso doméstico. Disponível em diversas cores metalizadas sólidas e degradê. Volume de 400ml, espessura de 2.2mm.', 'produto', NULL, 'CNCSML', '66', NULL, 400, 'UN', NULL, 73.00, '{"altura": 16.7, "espessura": 2.2, "altura_alca": 10.0, "diametro_inferior": 6.0, "diametro_superior": 7.0, "largura_total_com_alca": 10.0}'::jsonb, '{"linha": "Premium", "familia": "Caneca", "volume_ml": 400, "acabamento": "metalizado", "espessura_mm": 2.2, "caracteristicas": ["acabamento_metalizado", "interior_cromado", "design_premium", "com_alca", "variedade_cores", "cores_solidas", "cores_degrade", "uso_domestico", "uso_cafe_cha"], "interior_cromado": true}'::jsonb, true, true, '2025-11-13T12:44:18.339811+00:00'::timestamptz, '2025-11-13T12:44:18.339811+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('5ec1d32b-8b54-41ea-adaa-a85ee388a0f0', '918495eb-c6f9-422c-89cc-4132bc9b6480', 'twister-light-degrade', 'Twister Light Degradê 500ml', 'Copo Twister Light com acabamento degradê e bicolor, capacidade de 500ml. O produto inclui cores sólidas com efeito degradê e combinações bicolores.', 'produto', NULL, 'TWSLHTDL', '570', NULL, 500, 'UN', NULL, 51.00, '{"altura": 14.0, "espessura": 2, "diametro_inferior": 5.8, "diametro_superior": 8.5}'::jsonb, '{"familia": "Twister", "tamanho": "G", "volume_ml": 500, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Twister Light Fosco Incolor (twister-light-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto twister-light-fosco-incolor.", "espessura_mm": 2, "tipo_acabamento": "degrade", "produto_relacionado": "twister-light-fosco-incolor"}'::jsonb, true, true, '2025-11-13T16:20:24.325045+00:00'::timestamptz, '2025-11-13T16:20:24.325045+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('6516ffe0-bce7-448b-b1f2-59172c528829', '41b7d767-a952-49d3-a86a-b00bca9f1638', 'long-drink-premium-fosco-incolor', 'Long Drink Premium Fosco Incolor 340ml', 'Copo Long Drink Premium 340ml com acabamento fosco incolor (efeito gelado). Design elegante e moderno com efeito visual gelado/translúcido fosco, ideal para bebidas geladas e drinks. Volume de 340ml, espessura de 2.2mm, acabamento externo fosco incolor.', 'produto', NULL, 'LNGPFIL', '422', NULL, 340, 'UN', NULL, 53.00, '{"altura": 16.0, "espessura": 2.2, "diametro_inferior": 5.2, "diametro_superior": 6.1}'::jsonb, '{"efeito": "gelado", "familia": "Long Drink", "tamanho": "Premium", "volume_ml": 340, "acabamento": "fosco_incolor", "observacao": "Este produto é um SKU separado do degradê. Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', este é o produto correto.", "cor_externa": "fosco_incolor", "espessura_mm": 2.2, "caracteristicas": ["acabamento_fosco_incolor", "efeito_gelado", "design_elegante", "relacionado_degrade"], "produto_relacionado": "long-drink-premium-degrade", "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T14:03:26.400241+00:00'::timestamptz, '2025-11-13T14:03:26.400241+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('66249c18-21e5-426c-8c22-ec34b96b9211', '41b7d767-a952-49d3-a86a-b00bca9f1638', 'long-drink-fit-degrade', 'Long Drink Fit Degradê 250ml', 'Copo Long Drink Fit com efeito degradê e capacidade de 250ml. Design compacto e versátil com acabamento degradê disponível em cores simples (degradê para transparente) e bicolor (degradê entre duas cores). Ideal para bebidas geladas e drinks.', 'produto', NULL, 'LNGFDL', '488', NULL, 250, 'UN', NULL, 32.00, '{"altura": 14.0, "espessura": 1.5, "diametro_inferior": 4.7, "diametro_superior": 5.6}'::jsonb, '{"familia": "Long Drink", "tamanho": "Fit", "volume_ml": 250, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Long Drink Fit Fosco Incolor (long-drink-fit-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto long-drink-fit-fosco-incolor.", "espessura_mm": 1.5, "tipo_degrade": "simples_e_bicolor", "produto_relacionado": "long-drink-fit-fosco-incolor", "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:20:58.809214+00:00'::timestamptz, '2025-11-13T13:20:58.809214+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('664649a5-6669-40b8-afad-2f3044d17f9d', '4501591e-56a6-4910-bf1c-aa9790f1bcf2', 'caldereta-350-liso', 'Caldereta 350ml Liso', 'Caldereta 350ml com acabamento liso. Design premium e funcional, ideal para bebidas, festas e eventos. Disponível em diversas cores translúcidas, leitosas, neon e peroladas. Volume de 350ml, espessura de 2mm. Compatível com tampas tradicionais, Bucks, Chantilly e Baby (tamanho M).', 'produto', NULL, 'CLD35L', '3', NULL, 350, 'UN', NULL, 48.00, '{"altura": 11.5, "espessura": 2.0, "diametro_inferior": 5.9, "diametro_superior": 7.6}'::jsonb, '{"linha": "Premium", "familia": "Caldereta", "volume_ml": 350, "acabamento": "liso", "espessura_mm": 2.0, "caracteristicas": ["acabamento_liso", "design_premium", "variedade_cores", "uso_festas_eventos", "compativel_tampas"], "acessorios_compativel": ["tampa_tradicional_m", "tampa_bucks_m", "tampa_chantilly_m", "tampa_baby_m"], "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T12:10:02.979292+00:00'::timestamptz, '2025-11-13T12:10:02.979292+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('68e81bb0-3a39-4890-94bb-832000225c30', '87fddf11-6c05-46ea-b6a8-4a03082bd455', 'sobretampa-style', 'Sobretampa Style', 'Sobretampa Style (parte superior, com abertura para canudo). Produto complementar à Tampa Style base e ao Canudo G. IMPORTANTE: Para funcionar corretamente, é necessário comprar também a Tampa Style base e o Canudo G. A tampa base, a sobretampa e o canudo são vendidos separadamente e podem ser combinados em cores diferentes, permitindo criar combinações personalizadas. Exemplo: sobretampa preta com tampa base azul neon e canudo transparente, ou sobretampa creme marmorizado com tampa base branca e canudo rosa. Cada parte é vendida em pacotes de 10 unidades da mesma cor. Exclusiva e compatível com Eco Duo.', 'acessorio', NULL, 'STMPSTYLL', '1397', NULL, NULL, 'UN', NULL, 10.00, '{"altura": 1.1, "espessura": null, "diametro_inferior": 9.2, "diametro_superior": null}'::jsonb, '{"familia": "Tampa", "tipo_acessorio": "sobretampa_style", "exclusiva_eco_duo": true, "produto_complementar": "tampa-style", "explicacao_combinacao": "A Sobretampa Style é um produto complementar à Tampa Style base e ao Canudo G. São três produtos separados que funcionam juntos. O cliente pode comprar a sobretampa em uma cor, a tampa base em outra cor e o canudo em uma terceira cor, criando combinações personalizadas. Por exemplo: sobretampa preta + tampa base azul neon + canudo transparente, ou sobretampa creme marmorizado + tampa base branca + canudo rosa. Cada parte é vendida separadamente em pacotes de 10 unidades da mesma cor. É importante sempre informar ao cliente que precisa comprar os três produtos (tampa base, sobretampa e canudo) para ter a Tampa Style completa funcionando. Esta tampa é exclusiva e compatível com o Eco Duo.", "produto_complementar_2": "canudo-g", "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T09:58:43.106098+00:00'::timestamptz, '2025-11-13T09:58:43.106098+00:00'::timestamptz, NULL, NULL, NULL, NULL);
