INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('722a7fb6-ba43-4eb5-b3de-fb0b39d6e1b9', '41b7d767-a952-49d3-a86a-b00bca9f1638', 'long-drink-light-degrade', 'Long Drink Light Degradê 330ml', 'Copo Long Drink Light com efeito degradê (gradiente). Disponível em cores degradê simples (cor para branco) e degradê bicolor (duas cores). Produto leve e econômico. Todas as cores podem ser combinadas com borda metalizada.', 'produto', NULL, 'LNGLHTDL', '584', NULL, 330, 'UN', NULL, 42.00, '{"altura": 15.0, "espessura": 2.0, "diametro_inferior": 5.2, "diametro_superior": 6.1}'::jsonb, '{"familia": "Long Drink", "tamanho": "Light", "volume_ml": 330, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Long Drink Light Fosco Incolor (long-drink-light-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto long-drink-light-fosco-incolor.", "espessura_mm": 2.0, "tipo_degrade": "simples_e_bicolor", "produto_relacionado": "long-drink-light-fosco-incolor", "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T13:48:39.005791+00:00'::timestamptz, '2025-11-13T13:48:39.005791+00:00'::timestamptz, NULL, NULL, NULL, NULL);
