INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('7d02b160-c3c2-401b-9193-3759613ce746', '41b7d767-a952-49d3-a86a-b00bca9f1638', 'long-drink-fit-fosco-incolor', 'Long Drink Fit Fosco Incolor 250ml', 'Copo Long Drink Fit 250ml com acabamento fosco incolor (efeito gelado). Design compacto e versátil com efeito visual gelado/translúcido fosco, ideal para bebidas geladas e drinks. Volume de 250ml, espessura de 1.5mm, acabamento externo fosco incolor.', 'produto', NULL, 'LNGFFIL', '498', NULL, 250, 'UN', NULL, 32.00, '{"altura": 14.0, "espessura": 1.5, "diametro_inferior": 4.7, "diametro_superior": 5.6}'::jsonb, '{"efeito": "gelado", "familia": "Long Drink", "tamanho": "Fit", "volume_ml": 250, "acabamento": "fosco_incolor", "observacao": "Este produto é um SKU separado do degradê. Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', este é o produto correto.", "cor_externa": "fosco_incolor", "espessura_mm": 1.5, "caracteristicas": ["acabamento_fosco_incolor", "efeito_gelado", "design_compacto", "versatil", "relacionado_degrade"], "produto_relacionado": "long-drink-fit-degrade", "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:23:48.114546+00:00'::timestamptz, '2025-11-13T13:23:48.114546+00:00'::timestamptz, NULL, NULL, NULL, NULL);
