INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('8c805142-96c4-416e-8862-caecfb6c03d7', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-bio', 'Garrafa Acqua Bio', 'Garrafa Acqua Bio com acabamento liso. Design elegante e moderno, ideal para uso no dia a dia. Disponível em diversas cores neon, translúcidas, leitosas e com acabamento glitter. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', NULL, 'GABL', '396', NULL, 475, 'UN', NULL, 68.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Bio", "familia": "Garrafa", "volume_ml": 475, "acabamento": "liso", "espessura_mm": 2, "caracteristicas": ["acabamento_liso", "design_elegante", "variedade_cores"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:40:07.974793+00:00'::timestamptz, '2025-11-13T10:40:07.974793+00:00'::timestamptz, NULL, NULL, NULL, NULL);
