INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('99aa8f97-4254-499f-86e0-c520d9c8be5d', 'a2c0ccc8-273f-4606-9e75-62fa09a15939', 'taca-gin-fosco-incolor', 'Taça GIN Fosco Incolor 550ml', 'Taça GIN 550ml com acabamento fosco incolor (efeito gelado). Design elegante com efeito visual gelado/translúcido fosco, ideal para drinks e bebidas geladas. Dimensões: 19.7cm de altura, 10.2cm de diâmetro superior, 7.4cm de diâmetro inferior. Espessura de 3mm.', 'produto', NULL, 'TGFIL', '411', NULL, 550, 'UN', NULL, 82.00, '{"altura": 19.7, "espessura": 3, "diametro_inferior": 7.4, "diametro_superior": 10.2}'::jsonb, '{"efeito": "gelado", "familia": "Taça GIN", "tamanho": "550ml", "volume_ml": 550, "acabamento": "fosco_incolor", "observacao": "Este produto é um SKU separado do degradê. Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', este é o produto correto.", "cor_externa": "fosco_incolor", "espessura_mm": 3, "caracteristicas": ["acabamento_fosco_incolor", "efeito_gelado", "design_elegante", "relacionado_degrade"], "produto_relacionado": "taca-gin-degrade"}'::jsonb, true, true, '2025-11-13T14:37:27.945781+00:00'::timestamptz, '2025-11-13T14:42:55.474571+00:00'::timestamptz, NULL, NULL, NULL, NULL);
