INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('9e6a9c4d-ab0d-446c-98b7-ff50af139f41', '918495eb-c6f9-422c-89cc-4132bc9b6480', 'twister-premium-verde-fosco', 'Twister Premium Verde Fosco 550ml', 'Copo Twister Premium Verde Fosco com capacidade de 550ml. Design premium com externa verde fosca e interna preta. Pode ser combinado com borda metalizada.', 'produto', NULL, 'TWSPVFL', '2107', NULL, 550, 'UN', NULL, 70.00, '{"altura": 14.0, "espessura": 2, "diametro_inferior": 6.5, "diametro_superior": 8.5}'::jsonb, '{"familia": "Twister", "tamanho": "G", "novidade": true, "volume_ml": 550, "espessura_mm": 2, "interna_preta": true, "tipo_acabamento": "verde_fosco", "externa_verde_fosca": true, "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T16:37:16.206356+00:00'::timestamptz, '2025-11-13T16:37:16.206356+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('9fb4c332-1c6b-4526-9149-bf0bbc6a2f45', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-bio-fosco-incolor', 'Garrafa Acqua Bio Fosco Incolor', 'Garrafa Acqua Bio 475ml com acabamento fosco incolor (efeito gelado). Design elegante e moderno com efeito visual gelado/translúcido fosco, ideal para uso no dia a dia. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', NULL, 'GABFIL', '427', NULL, 475, 'UN', NULL, 68.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Bio", "efeito": "gelado", "familia": "Garrafa", "volume_ml": 475, "acabamento": "fosco_incolor_liso", "observacao": "Este produto é um SKU separado do degradê. Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', este é o produto correto.", "cor_externa": "fosco_incolor", "espessura_mm": 2, "caracteristicas": ["acabamento_fosco_incolor", "efeito_gelado", "design_elegante", "relacionado_degrade"], "produto_relacionado": "garrafa-acqua-bio-degrade", "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:27:37.416490+00:00'::timestamptz, '2025-11-13T10:27:37.416490+00:00'::timestamptz, NULL, NULL, NULL, NULL);
