INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('a15209b7-2c3e-4901-8e2b-10d186220885', '945ebc87-9c2d-47b6-aa1d-05b61c4f1b4e', 'eco-balde-liso', 'Eco Balde Liso 5L', 'Balde Eco com capacidade de 5 litros. Design ecológico e sustentável, ideal para gelo, bebidas geladas e armazenamento. Disponível em cores neon, leitosas, translúcidas e linha fibra (cores especiais com fibra de madeira). Produto com consciência ambiental.', 'produto', NULL, 'ECOBL', '394', NULL, 5000, 'UN', NULL, 245.00, '{"altura": 16.1, "espessura": 2.0, "diametro_inferior": 15.9, "diametro_superior": 21.1}'::jsonb, '{"familia": "Eco", "tamanho": "5L", "linha_eco": true, "volume_ml": 5000, "espessura_mm": 2.0, "uso_recomendado": ["gelo", "bebidas_geladas", "armazenamento", "refrigeracao"], "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:16:20.622754+00:00'::timestamptz, '2025-11-13T13:16:20.622754+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('a1ae9c8a-ed45-4750-91a1-6768cd3219e4', '87fddf11-6c05-46ea-b6a8-4a03082bd455', 'tampa-style', 'Tampa Style', 'Tampa Style base (parte inferior, mais larga). Produto complementar à Sobretampa Style e Canudo G. IMPORTANTE: Para funcionar corretamente, é necessário comprar também a Sobretampa Style e o Canudo G. A tampa base, a sobretampa e o canudo são vendidos separadamente e podem ser combinados em cores diferentes, permitindo criar combinações personalizadas. Exemplo: tampa base azul neon com sobretampa preta e canudo transparente, ou tampa base branca com sobretampa creme marmorizado e canudo rosa. Cada parte é vendida em pacotes de 10 unidades da mesma cor. Exclusiva e compatível com Eco Duo.', 'acessorio', NULL, 'TMPSTYLL', '1396', NULL, NULL, 'UN', NULL, 18.00, '{"altura": 1.2, "espessura": null, "diametro_inferior": 9.2, "diametro_superior": 9.2}'::jsonb, '{"familia": "Tampa", "tipo_acessorio": "tampa_style", "exclusiva_eco_duo": true, "produto_complementar": "sobretampa-style", "explicacao_combinacao": "A Tampa Style base é um produto complementar à Sobretampa Style e ao Canudo G. São três produtos separados que funcionam juntos. O cliente pode comprar a tampa base em uma cor, a sobretampa em outra cor e o canudo em uma terceira cor, criando combinações personalizadas. Por exemplo: tampa base azul neon + sobretampa preta + canudo transparente, ou tampa base branca + sobretampa creme marmorizado + canudo rosa. Cada parte é vendida separadamente em pacotes de 10 unidades da mesma cor. É importante sempre informar ao cliente que precisa comprar os três produtos (tampa base, sobretampa e canudo) para ter a Tampa Style completa funcionando. Esta tampa é exclusiva e compatível com o Eco Duo.", "produto_complementar_2": "canudo-g", "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T10:07:02.481724+00:00'::timestamptz, '2025-11-13T10:07:02.481724+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('a364d95f-68a5-4653-a570-fc58d9cb4ccc', '918495eb-c6f9-422c-89cc-4132bc9b6480', 'mini-twister-degrade', 'Mini Twister Degradê 350ml', 'Copo Mini Twister com acabamento degradê e bicolor, capacidade de 350ml. O produto inclui cores sólidas com efeito degradê e combinações bicolores. Todas as cores podem ser combinadas com borda metalizada.', 'produto', NULL, 'MTWSDL', '456', NULL, 350, 'UN', NULL, 50.00, '{"altura": 11.5, "espessura": 2, "diametro_inferior": 5.9, "diametro_superior": 7.6}'::jsonb, '{"familia": "Twister", "tamanho": "M", "volume_ml": 350, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Mini Twister Fosco Incolor (mini-twister-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto mini-twister-fosco-incolor.", "espessura_mm": 2, "tipo_acabamento": "degrade", "produto_relacionado": "mini-twister-fosco-incolor", "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T16:14:17.688941+00:00'::timestamptz, '2025-11-13T16:14:17.688941+00:00'::timestamptz, NULL, NULL, NULL, NULL);
