INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('a633fe91-e64a-4814-868e-73fbb4a07f71', '945ebc87-9c2d-47b6-aa1d-05b61c4f1b4e', 'eco-beer-liso', 'Eco Beer Liso 450ml', 'Copo Eco Beer com capacidade de 450ml. Design ecológico e sustentável, ideal para cervejas e bebidas geladas. Disponível em cores neon, leitosas, translúcidas e linha fibra (cores especiais com fibra de madeira). Produto com consciência ambiental.', 'produto', NULL, 'ECOBRL', '917', NULL, 450, 'UN', NULL, 41.00, '{"altura": 14.2, "espessura": 1.3, "diametro_inferior": 5.6, "diametro_superior": 8.4}'::jsonb, '{"familia": "Eco", "tamanho": "450ml", "linha_eco": true, "volume_ml": 450, "espessura_mm": 1.3, "uso_recomendado": ["cerveja", "bebidas_geladas", "refrigerantes", "sucos"], "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:17:11.671628+00:00'::timestamptz, '2025-11-13T13:17:11.671628+00:00'::timestamptz, NULL, NULL, NULL, NULL);
