INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('adb9dda9-7f6d-4ef0-a89c-6333cef0fccb', '87fddf11-6c05-46ea-b6a8-4a03082bd455', 'tampa-acqua-adventure', 'Tampa Acqua Adventure', 'Tampa Acqua Adventure base (parte inferior, mais larga). Produto complementar à Sobretampa Acqua Adventure. IMPORTANTE: Para funcionar corretamente, é necessário comprar também a Sobretampa Acqua Adventure. A tampa base e a sobretampa são vendidas separadamente e podem ser combinadas em cores diferentes, permitindo criar combinações personalizadas. Exemplo: tampa base azul com sobretampa preta, ou tampa base branca com sobretampa verde neon. Cada parte é vendida em pacotes de 10 unidades da mesma cor.', 'acessorio', NULL, 'TMPAADL', '1051', NULL, NULL, 'UN', NULL, 19.00, '{"altura": 4.0, "espessura": null, "diametro_inferior": 7.0, "diametro_superior": 7.0}'::jsonb, '{"familia": "Tampa", "tipo_acessorio": "tampa_acqua_adventure", "produto_complementar": "sobretampa-acqua-adventure", "altura_total_com_alca": 4.5, "explicacao_combinacao": "A Tampa Acqua Adventure base é um produto complementar à Sobretampa Acqua Adventure. São dois produtos separados que funcionam juntos. O cliente pode comprar a tampa base em uma cor e a sobretampa em outra cor, criando combinações personalizadas. Por exemplo: tampa base azul + sobretampa preta, ou tampa base branca + sobretampa verde neon. Cada parte é vendida separadamente em pacotes de 10 unidades da mesma cor. É importante sempre informar ao cliente que precisa comprar ambos os produtos para ter a Tampa Acqua Adventure completa funcionando.", "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T11:18:20.072227+00:00'::timestamptz, '2025-11-13T11:18:20.072227+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('afaaaf81-92c9-40a7-ab16-c303c2cef88a', 'c5a82071-1e01-4477-9cdc-f2bc2b6802d7', 'taca-light-metalizada-ip', 'Taça Light Metalizada I.P 190ml', 'Taça Light com capacidade de 190ml e acabamento metalizado com interior preto. Design leve e sofisticado para espumantes e champagnes. Disponível em cores metalizadas simples, combinações de duas tonalidades e Linha Brasil. Dimensões: 20cm de altura, 5.5cm de diâmetro superior, 6.5cm de diâmetro inferior. Espessura de 2mm, peso de 47g. Interior preto que proporciona visual elegante e moderno.', 'produto', NULL, 'TCALHTMIPL', '1834', NULL, 190, 'UN', NULL, 47.00, '{"altura": 20.0, "espessura": 2, "diametro_inferior": 6.5, "diametro_superior": 5.5}'::jsonb, '{"tipo": "champagne_flute", "linha": "Metalizada I.P", "familia": "Taça Light", "volume_ml": 190, "acabamento": "metalizado", "observacao": "IMAGEM ILUSTRATIVA: fotos projetadas sem sombras e reflexos naturais! Pinturas especiais podem apresentar marcas características do processo de pintura.", "espessura_mm": 2, "interna_preta": true, "caracteristicas": ["design_leve", "design_sofisticado", "metalizacao", "interna_preta", "variedade_cores", "duas_tonalidades", "linha_brasil", "uso_espumante", "uso_champagne", "ano_novo", "reveillon", "festas"], "acabamento_adicional": null}'::jsonb, true, true, '2025-11-13T16:03:21.474892+00:00'::timestamptz, '2025-11-13T16:03:21.474892+00:00'::timestamptz, NULL, NULL, NULL, NULL);
