INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('c8b57551-f873-4541-9b84-3d80632ca31a', '41b7d767-a952-49d3-a86a-b00bca9f1638', 'long-drink-premium-degrade', 'Long Drink Premium Degradê 340ml', 'Copo Long Drink Premium com efeito degradê (gradiente). Disponível em cores degradê simples (cor para branco) e degradê bicolor (duas cores). Inclui lançamentos especiais Arco-Íris e Summer. Todas as cores podem ser combinadas com borda metalizada.', 'produto', NULL, 'LNGPDL', '88', NULL, 340, 'UN', NULL, 53.00, '{"altura": 16.0, "espessura": 2.2, "diametro_inferior": 5.2, "diametro_superior": 6.1}'::jsonb, '{"familia": "Long Drink", "tamanho": "Premium", "volume_ml": 340, "observacao": "IMPORTANTE: A cor ''incolor efeito gelado'' não faz parte deste produto degradê. É um SKU separado: Long Drink Premium Fosco Incolor (long-drink-premium-fosco-incolor). Quando clientes perguntarem sobre ''degradê incolor'', ''degradê gelado'' ou ''incolor efeito gelado'', direcionar para o produto long-drink-premium-fosco-incolor.", "espessura_mm": 2.2, "tipo_degrade": "simples_e_bicolor", "produto_relacionado": "long-drink-premium-fosco-incolor", "permite_borda_metalizada": true}'::jsonb, true, true, '2025-11-13T14:00:39.902652+00:00'::timestamptz, '2025-11-13T14:00:39.902652+00:00'::timestamptz, NULL, NULL, NULL, NULL);
