INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('d9bea64f-756c-4f86-894b-c3eb2fd046e4', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-bio-metalizado-ip', 'Garrafa Acqua Bio Metalizado I.P', 'Garrafa Acqua Bio com acabamento metalizado e interna preta. Design elegante e moderno, ideal para uso no dia a dia. Disponível em diversas cores metalizadas sólidas e gradientes. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', 'Metalizado', 'GABMIPL', '1852', NULL, 475, 'UN', NULL, 68.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Bio", "familia": "Garrafa", "volume_ml": 475, "acabamento": "metalizado", "espessura_mm": 2, "caracteristicas": ["interna_preta", "acabamento_metalizado", "design_elegante"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:29:06.708286+00:00'::timestamptz, '2025-11-13T10:29:06.708286+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('dacf9729-17fa-4e99-8cbf-936e5098f1f5', '54a926bd-f1a5-4c0a-b18e-df61edc2f98d', 'garrafa-acqua-eco-degrade', 'Garrafa Acqua Eco Degradê', 'Garrafa Acqua Eco Degradê 475ml com acabamento bicolor em degradê. Material PP (polipropileno), design elegante e moderno com efeito degradê vibrante, ideal para uso no dia a dia. Disponível em diversas cores degradê combinando duas cores. Volume de 475ml, espessura de 2mm. IMPORTANTE: Para vedar a garrafa adequadamente, é recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure). As tampas não são obrigatórias, mas são altamente recomendadas para melhor vedação e praticidade.', 'produto', NULL, 'GAECODL', '896', NULL, 475, 'UN', NULL, 55.00, '{"altura": 17.8, "espessura": 2.0, "diametro_inferior": 6.1, "diametro_superior": 6.5}'::jsonb, '{"linha": "Acqua Eco", "familia": "Garrafa", "material": "PP", "volume_ml": 475, "acabamento": "degrade", "espessura_mm": 2, "caracteristicas": ["acabamento_degrade", "bicolor", "material_pp", "design_elegante", "efeito_degrade_vibrante"], "recomendacao_tampas": "É recomendado adquirir uma das tampas compatíveis (Tampa Acqua Bio Tradicional, Tampa Acqua Bio Premium ou Tampa Acqua Adventure) para melhor vedação. As tampas não são obrigatórias, mas são altamente recomendadas."}'::jsonb, true, true, '2025-11-13T10:41:21.114072+00:00'::timestamptz, '2025-11-13T10:41:21.114072+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('db373fab-bfa0-40d0-ac08-3efeff993d4f', '945ebc87-9c2d-47b6-aa1d-05b61c4f1b4e', 'eco-duo-liso', 'Eco Duo Liso 500ml', 'Copo Eco Duo com capacidade de 500ml. Design ecológico e sustentável com parede dupla (semi-térmico). Ideal para bebidas quentes e frias, mantendo a temperatura por mais tempo. Disponível em 6 combinações de cores com parte interna preta e parte externa variada. Produto com consciência ambiental e tecnologia de isolamento térmico.', 'produto', NULL, 'ECODL', '1409', NULL, 500, 'UN', NULL, 88.00, '{"altura": 16.0, "espessura_boca": 4.0, "espessura_parede": 2.0, "diametro_inferior": 6.2, "diametro_superior": 8.7}'::jsonb, '{"familia": "Eco", "tamanho": "500ml", "linha_eco": true, "volume_ml": 500, "parede_dupla": true, "semi_termico": true, "uso_recomendado": ["bebidas_quentes", "bebidas_frias", "cafe", "cha", "sucos"], "espessura_boca_mm": 4.0, "espessura_parede_mm": 2.0, "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T13:18:00.256205+00:00'::timestamptz, '2025-11-13T13:18:00.256205+00:00'::timestamptz, NULL, NULL, NULL, NULL);
