INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('ea97fb0d-cf64-4f27-ac36-ebde2c77853e', 'a2c0ccc8-273f-4606-9e75-62fa09a15939', 'taca-happy-gin-liso', 'Taça Gin Linha Happy 550ml', 'Taça Gin Linha Happy com capacidade de 550ml. Design elegante com base colorida e cuba translúcida ou leitosa. Disponível em diversas combinações de cores entre cuba e base, incluindo cores neon, leitosas, translúcidas e peroladas. Volume de 550ml, espessura de 3mm.', 'produto', NULL, 'THGL', '266', NULL, 550, 'UN', NULL, 82.00, '{"altura": 19.9, "espessura": 3.0, "diametro_inferior": 7.4, "diametro_superior": 10.2}'::jsonb, '{"linha": "Happy", "familia": "Taça Gin", "tamanho": "grande", "volume_ml": 550, "acabamento": "liso", "espessura_mm": 3.0, "caracteristicas": ["design_elegante", "base_colorida", "cuba_translucida", "cuba_leitosa", "variedade_cores", "uso_drinks", "uso_gin_tonica"], "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T15:50:47.528217+00:00'::timestamptz, '2025-11-13T15:50:47.528217+00:00'::timestamptz, NULL, NULL, NULL, NULL);
INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('ebb7a6aa-6207-4f28-a5ef-90e63e57bd0c', '87fddf11-6c05-46ea-b6a8-4a03082bd455', 'sobretampa-shake', 'Sobretampa Shake', 'Sobretampa Shake (parte superior, central). Produto complementar à Tampa Shake base. IMPORTANTE: Para funcionar corretamente, é necessário comprar também a Tampa Shake base. A tampa base e a sobretampa são vendidas separadamente e podem ser combinadas em cores diferentes, permitindo criar combinações personalizadas. Exemplo: sobretampa preta com tampa base azul, ou sobretampa verde neon com tampa base branca. Cada parte é vendida em pacotes de 10 unidades da mesma cor. O cliente pode comprar 1 sobretampa e várias tampas base coloridas, ou vice-versa.', 'acessorio', NULL, 'STMPSKL', '1004', NULL, NULL, 'UN', NULL, 5.00, '{"altura": 7.8, "espessura": null, "diametro_inferior": 3.0, "diametro_superior": null}'::jsonb, '{"familia": "Tampa", "tipo_acessorio": "sobretampa_shake", "produto_complementar": "tampa-shake", "explicacao_combinacao": "A Sobretampa Shake é um produto complementar à Tampa Shake base. São dois produtos separados que funcionam juntos. O cliente pode comprar a sobretampa em uma cor e a tampa base em outra cor, criando combinações personalizadas. Por exemplo: sobretampa preta + tampa base azul, ou sobretampa verde neon + tampa base branca. Cada parte é vendida separadamente em pacotes de 10 unidades da mesma cor. O cliente pode comprar 1 sobretampa e várias tampas base coloridas, ou vice-versa. É importante sempre informar ao cliente que precisa comprar ambos os produtos para ter a Tampa Shake completa funcionando.", "permite_combinacao_cores": true}'::jsonb, true, true, '2025-11-13T09:54:19.922999+00:00'::timestamptz, '2025-11-13T09:54:19.922999+00:00'::timestamptz, NULL, NULL, NULL, NULL);
