INSERT INTO catalogo.itens (id, categoria_id, slug, nome, descricao, tipo_item, linha_produto, sku_base, erp_id, erp_sync_em, capacidade_ml, unidade_medida, peso_unitario_g, peso_unit_g, dimensoes_cm, metadata, ativo, visivel_catalogo, criado_em, atualizado_em, criado_por, atualizado_por, url_imagem, url_diretorio) VALUES ('f0dc90e9-87fd-4d44-9156-904b5b0376f9', '4501591e-56a6-4910-bf1c-aa9790f1bcf2', 'caldereta-350-preto-fosco-liso', 'Caldereta Preto Fosco 350ml Liso', 'Caldereta 350ml com acabamento preto fosco (matte black) e interior colorido. Design premium e funcional, ideal para bebidas, festas e eventos. Disponível em diversas cores leitosas no interior. Volume de 350ml, espessura de 2mm. Acabamento fosco elegante com opções de cores vibrantes no interior. Compatível com tampas tradicionais, Bucks, Chantilly e Baby (tamanho M).', 'produto', NULL, 'CLD35PFL', '502', NULL, 350, 'UN', NULL, 50.00, '{"altura": 11.5, "espessura": 2.0, "diametro_inferior": 5.9, "diametro_superior": 7.6}'::jsonb, '{"linha": "Premium", "familia": "Caldereta", "volume_ml": 350, "acabamento": "preto_fosco", "espessura_mm": 2.0, "caracteristicas": ["acabamento_preto_fosco", "design_premium", "interior_colorido", "variedade_cores_interior", "uso_festas_eventos", "compativel_tampas", "acabamento_matte"], "acessorios_compativel": ["tampa_tradicional_m", "tampa_bucks_m", "tampa_chantilly_m", "tampa_baby_m"], "permite_borda_metalizada": false}'::jsonb, true, true, '2025-11-13T12:11:44.495891+00:00'::timestamptz, '2025-11-13T12:11:44.495891+00:00'::timestamptz, NULL, NULL, NULL, NULL);
